#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int ans = 0;
        for (int i = 0; i <= N - K; ++i) {
            int bitwise_or = 0;
            for (int j = i; j < i + K; ++j) {
                bitwise_or |= A[j];
            }
            if (bitwise_or & 1) ++ans;
        }
        printf("%d\n", ans);
        free(A);
    }
    return 0;
}

