import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        ans = 0
        for i in range(N - K + 1):
            bitwise_or = 0
            for j in range(i, i + K):
                bitwise_or |= A[j]
            if bitwise_or & 1:
                ans += 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

